<script setup lang="ts">
import { computed, ref } from 'vue'
import { useRoute } from 'vue-router'
import { VueDraggable } from 'vue-draggable-plus'
import { ArrowLeft, Check, ChevronRight, Eye, GripVertical, Heading, LayoutTemplate, ListChecks, MessageSquare, Music2, Plus, Save, Settings2, Text, Trash2 } from 'lucide-vue-next'
import UiButton from '@/components/ui/button/UiButton.vue'
import UiSwitch from '@/components/ui/switch/UiSwitch.vue'
import { useCourseStore } from '@/stores/courses'
import type { BlockType, LessonBlock } from '@/types/course'

const route=useRoute();const store=useCourseStore();const found=computed(()=>store.findLesson(String(route.params.lessonId)))
const blocks=computed<LessonBlock[]>({get:()=>found.value?.lesson.blocks??[],set:value=>{if(found.value)found.value.lesson.blocks=value}})
const selectedId=ref('');const selected=computed(()=>blocks.value.find(item=>item.id===selectedId.value)??blocks.value[0])
const saving=ref(false);const orderSaving=ref(false);const saved=ref(false);const editorError=ref('');let saveTimer:ReturnType<typeof setTimeout>|undefined
const palette:Array<{type:BlockType;label:string;description:string;icon:typeof Heading}>=[{type:'heading',label:'Заголовок',description:'Название раздела',icon:Heading},{type:'text',label:'Текст',description:'Основной материал',icon:Text},{type:'callout',label:'Акцент',description:'Важная мысль',icon:MessageSquare},{type:'audio',label:'Аудио',description:'Запись или диалог',icon:Music2},{type:'single_choice',label:'Тест',description:'Один вариант',icon:ListChecks}]
const blockLabel:Record<BlockType,string>={heading:'Заголовок',text:'Текст',callout:'Акцент',audio:'Аудио',single_choice:'Тест'}
async function add(type:BlockType){if(!found.value)return;await store.addBlock(found.value.lesson.id,type);selectedId.value=blocks.value.at(-1)?.id??''}
function scheduleSave(){saving.value=true;clearTimeout(saveTimer);saveTimer=setTimeout(async()=>{if(!found.value)return;try{await store.saveLesson(found.value.lesson.id);if(selected.value)await store.saveBlock(found.value.lesson.id,selected.value.id);saved.value=true;setTimeout(()=>saved.value=false,1200)}catch(error){editorError.value=error instanceof Error?error.message:'Не удалось сохранить'}finally{saving.value=false}},800)}
async function persistOrder(){if(!found.value)return;orderSaving.value=true;try{await store.persistBlockOrder(found.value.lesson.id);saved.value=true;setTimeout(()=>saved.value=false,1200)}catch(error){editorError.value=error instanceof Error?error.message:'Не удалось сохранить порядок'}finally{orderSaving.value=false}}
async function remove(){if(!found.value||!selected.value)return;await store.removeBlock(found.value.lesson.id,selected.value.id);selectedId.value=blocks.value[0]?.id??''}
async function publish(){if(!found.value)return;found.value.lesson.status='Опубликован';await store.saveLesson(found.value.lesson.id);saved.value=true}
function updateOptions(event:Event){if(!selected.value)return;selected.value.options=(event.target as HTMLTextAreaElement).value.split('\n').filter(Boolean);scheduleSave()}
</script>

<template><div v-if="found" class="product-editor"><header class="product-editor-topbar"><RouterLink :to="`/app/courses/${found.course.id}`" class="editor-back"><ArrowLeft/></RouterLink><div class="editor-crumbs"><span>{{found.course.title}}</span><ChevronRight/><strong>{{found.lesson.title}}</strong></div><div class="editor-save-state"><span v-if="saving||orderSaving">Сохраняем…</span><span v-else-if="saved"><Check/>Сохранено</span></div><RouterLink :to="`/preview/lessons/${found.lesson.id}`" class="product-button product-button--secondary"><Eye/>Предпросмотр</RouterLink><UiButton @click="publish"><Save/>{{found.lesson.status==='Опубликован'?'Опубликовано':'Опубликовать'}}</UiButton></header><aside class="product-palette"><div class="editor-panel-title"><LayoutTemplate/><div><strong>Библиотека</strong><small>Добавьте блок в урок</small></div></div><div class="palette-list"><button v-for="item in palette" :key="item.type" @click="add(item.type)"><span><component :is="item.icon"/></span><div><strong>{{item.label}}</strong><small>{{item.description}}</small></div><Plus/></button></div><div class="palette-tip"><GripVertical/><p>После добавления перетащите блок за маркер, чтобы изменить порядок.</p></div></aside><main class="product-canvas"><div v-if="editorError" class="product-alert is-error">{{editorError}}</div><div class="editor-document-head"><span>Урок · {{found.lesson.duration}} минут</span><input v-model="found.lesson.title" aria-label="Название урока" @input="scheduleSave"/><p>Соберите материал в логичную последовательность. Изменения сохраняются автоматически.</p></div><VueDraggable v-model="blocks" item-key="id" handle=".block-drag-handle" :animation="180" ghost-class="drag-ghost" :force-fallback="true" fallback-class="drag-fallback" chosen-class="drag-chosen" class="editor-block-list" @end="persistOrder"><article v-for="(item,index) in blocks" :key="item.id" :class="['product-editor-block',selected?.id===item.id&&'is-selected']" @click="selectedId=item.id"><button class="drag-handle block-drag-handle" aria-label="Переместить блок"><GripVertical/></button><div class="editor-block-number">{{String(index+1).padStart(2,'0')}}</div><div class="editor-block-content"><span>{{blockLabel[item.type]}}</span><h2 v-if="item.type==='heading'">{{item.content}}</h2><p v-else-if="item.type==='text'">{{item.content}}</p><aside v-else-if="item.type==='callout'"><MessageSquare/><div><strong>{{item.title}}</strong><p>{{item.content}}</p></div></aside><button v-else-if="item.type==='audio'" class="editor-audio" @click.stop><Music2/><span><strong>{{item.content}}</strong><small>Аудиоматериал</small></span></button><div v-else class="editor-question"><strong>{{item.content}}</strong><span v-for="(option,optionIndex) in item.options" :key="`${option}-${optionIndex}`">{{String.fromCharCode(65+optionIndex)}}. {{option}}</span></div></div></article></VueDraggable><button class="editor-insert" @click="add('text')"><Plus/>Добавить блок</button><div v-if="!blocks.length" class="product-empty"><LayoutTemplate/><h3>Урок пока пуст</h3><p>Выберите первый блок в библиотеке слева.</p></div></main><aside class="product-inspector"><div class="editor-panel-title"><Settings2/><div><strong>Настройки</strong><small>{{selected?blockLabel[selected.type]:'Блок не выбран'}}</small></div></div><template v-if="selected"><label>Название блока<input v-model="selected.title" @input="scheduleSave"/></label><label>Содержимое<textarea v-model="selected.content" @input="scheduleSave"></textarea></label><label v-if="selected.options">Варианты ответа<textarea :value="selected.options.join('\n')" @input="updateOptions"></textarea></label><div class="inspector-row"><div><strong>Обязательный</strong><small>Нужен для завершения урока</small></div><UiSwitch v-model="selected.required" @update:model-value="scheduleSave"/></div><button class="inspector-delete" @click="remove"><Trash2/>Удалить блок</button></template><div v-else class="inspector-empty"><Settings2/><p>Выберите блок на холсте, чтобы изменить его параметры.</p></div></aside></div><section v-else class="product-empty full"><LayoutTemplate/><h2>Урок не найден</h2><RouterLink to="/app/courses" class="product-button">Вернуться к курсам</RouterLink></section></template>